module.exports = { simulateSwap };

/**
 * @param {{ web3: any; userAddress: string; inToken: string; outToken: string; inAmount: string; swapTarget: string; swapApprovalTarget: string; swapCallData: string; recipient: string; extraTransfers: string}} params
 */
async function simulateSwap(params) {
  let {
    web3,
    userAddress,
    inToken,
    outToken,
    inAmount,
    swapTarget,
    swapApprovalTarget,
    swapCallData,
    recipient,
    extraTransfers,
  } = params;
  swapApprovalTarget = swapApprovalTarget || swapTarget;
  recipient = recipient || userAddress;
  extraTransfers = extraTransfers || "1";
  try {
    web3.eth.extend({
      methods: [
        {
          name: "callWithState",
          call: "eth_call",
          params: 3,
        },
      ],
    });

    const calls = [balanceOf(web3, outToken, recipient), approve(web3, inToken, swapApprovalTarget, inAmount)];
    for (let i = 0; i < Number(extraTransfers); i++) {
      calls.push(transferAll(web3, userAddress, inToken, userAddress));
    }
    calls.push({ target: swapTarget, callData: swapCallData });
    for (let i = 0; i < Number(extraTransfers); i++) {
      calls.push(transferAll(web3, recipient, outToken, recipient));
    }
    calls.push(balanceOf(web3, outToken, recipient));

    const result = await web3.eth.callWithState(
      {
        to: userAddress,
        data: web3.eth.abi.encodeFunctionCall(multicallAggregateAbi, [calls]),
      },
      "latest",
      {
        [mc]: { code: MULTISPY_BYTECODE },
        [userAddress]: { code: MULTISPY_BYTECODE },
        [recipient]: { code: MULTISPY_BYTECODE },
      }
    );
    const results = web3.eth.abi.decodeParameters(multicallAggregateAbi.outputs, result)[1];

    const startBalance = web3.eth.abi.decodeParameters([{ name: "outBalance", type: "uint256" }], results[0])[0];
    const endBalance = web3.eth.abi.decodeParameters(
      [{ name: "outBalance", type: "uint256" }],
      results[calls.length - 1]
    )[0];
    const outAmount = BigInt(endBalance) - BigInt(startBalance);
    if (outAmount <= 0) throw new Error("invalid output amount");

    return { success: true, outAmount: outAmount.toString(), gasCost: "0" };
  } catch (e) {
    return { success: false, error: e.message, outAmount: "0", gasCost: "0" };
  }
}

const approve = (web3, token, spender, amount) => ({
  target: token,
  callData: web3.eth.abi.encodeFunctionCall(
    {
      name: "approve",
      type: "function",
      inputs: [
        {
          type: "address",
          name: "spender",
        },
        {
          type: "uint256",
          name: "amount",
        },
      ],
    },
    [spender, amount]
  ),
});

const transferAll = (web3, sender, token, recipient) => ({
  target: sender,
  callData: web3.eth.abi.encodeFunctionCall(
    {
      name: "transferAll",
      type: "function",
      inputs: [
        {
          type: "address",
          name: "token",
        },
        {
          type: "address",
          name: "recipient",
        },
      ],
    },
    [token, recipient]
  ),
});

const balanceOf = (web3, token, target) =>
  isNativeAddress(token)
    ? {
        target: mc,
        callData: web3.eth.abi.encodeFunctionCall(
          {
            name: "getEthBalance",
            type: "function",
            inputs: [
              {
                type: "address",
                name: "account",
              },
            ],
          },
          [target]
        ),
      }
    : {
        target: token,
        callData: web3.eth.abi.encodeFunctionCall(
          {
            name: "balanceOf",
            type: "function",
            inputs: [
              {
                type: "address",
                name: "account",
              },
            ],
          },
          [target]
        ),
      };

const nativeTokenAddresses = [
  "0x0000000000000000000000000000000000000000",
  "0x0000000000000000000000000000000000001010",
  "0xEeeeeEeeeEeEeeEeEeEeeEEEeeeeEeeeeeeeEEeE",
  "0x000000000000000000000000000000000000dEaD",
  "0x000000000000000000000000000000000000800A",
];

const mc = "0x0000000000000000000000000000000000001234";

const isNativeAddress = (address) =>
  !!nativeTokenAddresses.find((a) => a == address || a.toLowerCase() === address.toLowerCase());

const multicallAggregateAbi = {
  constant: false,
  inputs: [
    {
      components: [
        { name: "target", type: "address" },
        { name: "callData", type: "bytes" },
      ],
      name: "calls",
      type: "tuple[]",
    },
  ],
  name: "aggregate",
  outputs: [
    { name: "blockNumber", type: "uint256" },
    { name: "returnData", type: "bytes[]" },
  ],
  payable: false,
  stateMutability: "nonpayable",
  type: "function",
};

const MULTISPY_BYTECODE =
  "";
